539→func (h *Handler) send(resp Response) error {
540→	data, err := json.Marshal(resp)
541→	if err != nil {
542→		return fmt.Errorf("marshaling response: %w", err)
543→	}
544→	line := string(data) + "\n"
545→	h.log.Log(context.Background(), LevelTrace, "Sent", "raw", string(data))
546→	_, err = io.WriteString(h.writer, line)
547→	return err
548→}
